    &lt;script&gt;
        const canvas = document.getElementById('canvas');
        const ctx = canvas.getContext('2d');

        function generateMagicTower() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            
            const centerX = canvas.width / 2;
            const centerY = canvas.height / 2;
            
            // 塔基 - 灰色石砖
            ctx.fillStyle = '#8b8b8b';
            ctx.beginPath();
            ctx.moveTo(centerX - 80, centerY + 60);
            ctx.lineTo(centerX + 80, centerY + 60);
            ctx.lineTo(centerX + 60, centerY - 20);
            ctx.lineTo(centerX - 60, centerY - 20);
            ctx.closePath();
            ctx.fill();
            
            // 塔基阴影
            ctx.fillStyle = '#6b6b6b';
            ctx.beginPath();
            ctx.moveTo(centerX + 80, centerY + 60);
            ctx.lineTo(centerX + 60, centerY - 20);
            ctx.lineTo(centerX + 60, centerY - 20);
            ctx.lineTo(centerX + 80, centerY - 40);
            ctx.closePath();
            ctx.fill();
            
            // 塔基高亮
            ctx.fillStyle = '#9b9b9b';
            ctx.beginPath();
            ctx.moveTo(centerX - 80, centerY + 60);
            ctx.lineTo(centerX - 60, centerY - 20);
            ctx.lineTo(centerX - 80, centerY - 40);
            ctx.closePath();
            ctx.fill();
            
            // 塔身 - 深紫灰色
            ctx.fillStyle = '#4a3b6b';
            ctx.beginPath();
            ctx.moveTo(centerX - 60, centerY - 20);
            ctx.lineTo(centerX + 60, centerY - 20);
            ctx.lineTo(centerX + 45, centerY - 120);
            ctx.lineTo(centerX - 45, centerY - 120);
            ctx.closePath();
            ctx.fill();
            
            // 塔身侧面阴影
            ctx.fillStyle = '#3a2b5b';
            ctx.beginPath();
            ctx.moveTo(centerX + 60, centerY - 20);
            ctx.lineTo(centerX + 45, centerY - 120);
            ctx.lineTo(centerX + 60, centerY - 130);
            ctx.lineTo(centerX + 80, centerY - 40);
            ctx.closePath();
            ctx.fill();
            
            // 塔身侧面高光
            ctx.fillStyle = '#5a4b7b';
            ctx.beginPath();
            ctx.moveTo(centerX - 60, centerY - 20);
            ctx.lineTo(centerX - 45, centerY - 120);
            ctx.lineTo(centerX - 60, centerY - 130);
            ctx.lineTo(centerX - 80, centerY - 40);
            ctx.closePath();
            ctx.fill();
            
            // 塔顶 - 魔法蓝紫色
            ctx.fillStyle = '#6c5ce7';
            ctx.beginPath();
            ctx.moveTo(centerX - 50, centerY - 120);
            ctx.lineTo(centerX, centerY - 200);
            ctx.lineTo(centerX + 50, centerY - 120);
            ctx.closePath();
            ctx.fill();
            
            // 塔顶侧面阴影
            ctx.fillStyle = '#5a4ac7';
            ctx.beginPath();
            ctx.moveTo(centerX + 50, centerY - 120);
            ctx.lineTo(centerX, centerY - 200);
            ctx.lineTo(centerX + 60, centerY - 130);
            ctx.closePath();
            ctx.fill();
            
            // 魔法水晶
            ctx.fillStyle = '#a29bfe';
            ctx.beginPath();
            ctx.moveTo(centerX, centerY - 200);
            ctx.lineTo(centerX - 15, centerY - 185);
            ctx.lineTo(centerX - 10, centerY - 170);
            ctx.lineTo(centerX + 10, centerY - 170);
            ctx.lineTo(centerX + 15, centerY - 185);
            ctx.closePath();
            ctx.fill();
            
            // 水晶发光效果
            const gradient = ctx.createRadialGradient(centerX, centerY - 185, 0, centerX, centerY - 185, 40);
            gradient.addColorStop(0, 'rgba(162, 155, 254, 0.6)');
            gradient.addColorStop(1, 'rgba(162, 155, 254, 0)');
            ctx.fillStyle = gradient;
            ctx.beginPath();
            ctx.arc(centerX, centerY - 185, 40, 0, Math.PI * 2);
            ctx.fill();
            
            // 魔法符文 - 塔身上
            ctx.fillStyle = '#ffd700';
            ctx.font = '16px Arial';
            ctx.textAlign = 'center';
            ctx.fillText('✧', centerX - 25, centerY - 60);
            ctx.fillText('✦', centerX, centerY - 80);
            ctx.fillText('✧', centerX + 25, centerY - 60);
            
            // 魔法粒子效果
            for (let i = 0; i &lt; 8; i++) {
                const angle = (i / 8) * Math.PI * 2;
                const radius = 70;
                const px = centerX + Math.cos(angle) * radius;
                const py = centerY - 100 + Math.sin(angle) * radius * 0.5;
                
                ctx.fillStyle = i % 2 === 0 ? '#a29bfe' : '#fd79a8';
                ctx.beginPath();
                ctx.arc(px, py, 4, 0, Math.PI * 2);
                ctx.fill();
            }
            
            // 石砖纹理 - 塔基
            ctx.strokeStyle = '#5a5a5a';
            ctx.lineWidth = 2;
            
            // 水平线条
            for (let y = centerY + 50; y &gt; centerY - 10; y -= 15) {
                ctx.beginPath();
                ctx.moveTo(centerX - 75, y);
                ctx.lineTo(centerX + 75, y);
                ctx.stroke();
            }
            
            // 垂直线条
            for (let x = centerX - 70; x &lt; centerX + 70; x += 20) {
                ctx.beginPath();
                ctx.moveTo(x, centerY + 55);
                ctx.lineTo(x - 10, centerY - 15);
                ctx.stroke();
            }
            
            // 轮廓线
            ctx.strokeStyle = '#2d2d44';
            ctx.lineWidth = 3;
            ctx.beginPath();
            ctx.moveTo(centerX - 80, centerY + 60);
            ctx.lineTo(centerX + 80, centerY + 60);
            ctx.lineTo(centerX + 60, centerY - 130);
            ctx.lineTo(centerX, centerY - 200);
            ctx.lineTo(centerX - 60, centerY - 130);
            ctx.closePath();
            ctx.stroke();
        }

        function downloadPNG() {
            const link = document.createElement('a');
            link.download = 'magic_tower.png';
            link.href = canvas.toDataURL('image/png');
            link.click();
        }

        // 初始生成
        generateMagicTower();
    &lt;/script&gt;
