using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine.UI;

namespace Sttop5.Modules.HomeBase.Editor
{
    /// <summary>
    /// 家园场景一键配置工具。
    /// 菜单：HomeBase/Setup HomeScene
    /// </summary>
    public static class HomeSceneSetup
    {
        [MenuItem("HomeBase/Setup HomeScene")]
        public static void SetupHomeScene()
        {
            // 确保在 HomeScene 中
            var scene = EditorSceneManager.GetActiveScene();
            if (!scene.name.Contains("HomeScene"))
            {
                // 尝试打开 HomeScene
                string path = "Assets/_Modules/HomeBase/Scenes/HomeScene.scene";
                if (System.IO.File.Exists(path))
                {
                    EditorSceneManager.OpenScene(path);
                }
                else
                {
                    EditorUtility.DisplayDialog("错误", "找不到 HomeScene.scene", "确定");
                    return;
                }
            }

            // 1. 创建管理器
            var managersParent = FindOrCreate("--- MANAGERS ---");

            var homeManagerGO = FindOrCreate("HomeManager", managersParent.transform);
            EnsureComponent<HomeManager>(homeManagerGO);

            var buildingManagerGO = FindOrCreate("BuildingManager", managersParent.transform);
            EnsureComponent<BuildingManager>(buildingManagerGO);

            var resourceManagerGO = FindOrCreate("ResourceManager", managersParent.transform);
            EnsureComponent<ResourceManager>(resourceManagerGO);

            // 2. 创建主相机（2D）
            var mainCamera = Camera.main;
            if (mainCamera == null)
            {
                var camGO = FindOrCreate("Main Camera");
                mainCamera = camGO.AddComponent<Camera>();
                camGO.tag = "MainCamera";
            }
            mainCamera.orthographic = true;
            mainCamera.orthographicSize = 5;
            mainCamera.transform.position = new Vector3(4.5f, 3.5f, -10);
            mainCamera.backgroundColor = new Color(0.15f, 0.25f, 0.15f);

            // 3. 创建网格背景
            CreateGridBackground();

            // 4. 创建 Canvas UI
            CreateHomeUI(homeManagerGO, buildingManagerGO, resourceManagerGO);

            // 5. 创建事件系统
            if (UnityEngine.EventSystems.EventSystem.current == null)
            {
                var esGO = new GameObject("EventSystem");
                esGO.AddComponent<UnityEngine.EventSystems.EventSystem>();
                esGO.AddComponent<UnityEngine.EventSystems.StandaloneInputModule>();
            }

            // 标记场景已修改
            EditorSceneManager.MarkSceneDirty(scene);
            Debug.Log("[HomeSceneSetup] 家园场景配置完成！");
            EditorUtility.DisplayDialog("完成", "家园场景配置完成！", "确定");
        }

        #region 辅助方法

        private static GameObject FindOrCreate(string name, Transform parent = null)
        {
            var go = GameObject.Find(name);
            if (go == null)
            {
                go = new GameObject(name);
                if (parent != null)
                    go.transform.SetParent(parent);
            }
            return go;
        }

        private static void EnsureComponent<T>(GameObject go) where T : Component
        {
            if (go.GetComponent<T>() == null)
            {
                go.AddComponent<T>();
                Debug.Log($"[Setup] Added {typeof(T).Name} to {go.name}");
            }
        }

        private static void CreateGridBackground()
        {
            var gridParent = FindOrCreate("--- GRID ---");

            // 创建一个绿色草地背景
            var bgGO = FindOrCreate("GrassBG", gridParent.transform);
            var sr = bgGO.GetComponent<SpriteRenderer>();
            if (sr == null) sr = bgGO.AddComponent<SpriteRenderer>();

            // 创建一个简单的绿色纹理
            var tex = new Texture2D(1, 1);
            tex.SetPixel(0, 0, new Color(0.3f, 0.6f, 0.2f));
            tex.Apply();

            sr.sprite = Sprite.Create(tex, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f), 1);
            bgGO.transform.position = new Vector3(4.5f, 3.5f, 0);
            bgGO.transform.localScale = new Vector3(10, 8, 1);
            sr.sortingOrder = -10;

            // 创建网格线（用 LineRenderer 或简单的 Sprite）
            for (int x = 0; x <= 10; x++)
            {
                var lineGO = new GameObject($"GridLine_V_{x}");
                lineGO.transform.SetParent(gridParent.transform);
                lineGO.transform.position = new Vector3(x, 4, 0);
                var lineSR = lineGO.AddComponent<SpriteRenderer>();
                var lineTex = new Texture2D(1, 1);
                lineTex.SetPixel(0, 0, new Color(0.2f, 0.4f, 0.15f, 0.5f));
                lineTex.Apply();
                lineSR.sprite = Sprite.Create(lineTex, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f), 1);
                lineGO.transform.localScale = new Vector3(0.02f, 8, 1);
                lineSR.sortingOrder = -9;
            }

            for (int y = 0; y <= 8; y++)
            {
                var lineGO = new GameObject($"GridLine_H_{y}");
                lineGO.transform.SetParent(gridParent.transform);
                lineGO.transform.position = new Vector3(4.5f, y, 0);
                var lineSR = lineGO.AddComponent<SpriteRenderer>();
                var lineTex = new Texture2D(1, 1);
                lineTex.SetPixel(0, 0, new Color(0.2f, 0.4f, 0.15f, 0.5f));
                lineTex.Apply();
                lineSR.sprite = Sprite.Create(lineTex, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f), 1);
                lineGO.transform.localScale = new Vector3(10, 0.02f, 1);
                lineSR.sortingOrder = -9;
            }
        }

        private static void CreateHomeUI(GameObject homeManagerGO, GameObject buildingManagerGO, GameObject resourceManagerGO)
        {
            // 创建 Canvas
            var canvasGO = FindOrCreate("Canvas");
            var canvas = canvasGO.GetComponent<Canvas>();
            if (canvas == null) canvas = canvasGO.AddComponent<Canvas>();
            canvas.renderMode = RenderMode.ScreenSpaceOverlay;
            canvas.sortingOrder = 100;

            var canvasScaler = canvasGO.GetComponent<CanvasScaler>();
            if (canvasScaler == null) canvasScaler = canvasGO.AddComponent<CanvasScaler>();
            canvasScaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
            canvasScaler.referenceResolution = new Vector2(1920, 1080);

            if (canvasGO.GetComponent<GraphicRaycaster>() == null)
                canvasGO.AddComponent<GraphicRaycaster>();

            // 资源栏
            CreateResourceBar(canvasGO);

            // 收集按钮
            CreateCollectButton(canvasGO);

            // 添加 HomeMainUI 组件
            var homeUI = canvasGO.GetComponent<HomeMainUI>();
            if (homeUI == null)
            {
                homeUI = canvasGO.AddComponent<HomeMainUI>();
                // 通过 SerializedObject 设置引用
                var so = new SerializedObject(homeUI);
                so.FindProperty("_homeManager").objectReferenceValue = homeManagerGO.GetComponent<HomeManager>();
                so.FindProperty("_buildingManager").objectReferenceValue = buildingManagerGO.GetComponent<BuildingManager>();
                so.FindProperty("_resourceManager").objectReferenceValue = resourceManagerGO.GetComponent<ResourceManager>();
                so.ApplyModifiedProperties();
            }
        }

        private static void CreateResourceBar(GameObject canvas)
        {
            var barGO = new GameObject("ResourceBar");
            barGO.transform.SetParent(canvas.transform, false);

            var rt = barGO.AddComponent<RectTransform>();
            rt.anchorMin = new Vector2(0, 1);
            rt.anchorMax = new Vector2(1, 1);
            rt.pivot = new Vector2(0.5f, 1);
            rt.sizeDelta = new Vector2(0, 60);
            rt.anchoredPosition = Vector2.zero;

            var bg = barGO.AddComponent<Image>();
            bg.color = new Color(0, 0, 0, 0.7f);

            // 创建资源文本
            float xPos = 20;
            CreateResourceText(barGO, "GoldText", "金币: 0", ref xPos);
            CreateResourceText(barGO, "DiamondText", "钻石: 0", ref xPos);
            CreateResourceText(barGO, "WoodText", "木材: 0", ref xPos);
            CreateResourceText(barGO, "LevelText", "Lv.1", ref xPos);
        }

        private static void CreateResourceText(GameObject parent, string name, string defaultText, ref float xPos)
        {
            var textGO = new GameObject(name);
            textGO.transform.SetParent(parent.transform, false);

            var rt = textGO.AddComponent<RectTransform>();
            rt.anchorMin = new Vector2(0, 0);
            rt.anchorMax = new Vector2(0, 1);
            rt.pivot = new Vector2(0, 0.5f);
            rt.sizeDelta = new Vector2(150, 0);
            rt.anchoredPosition = new Vector2(xPos, 0);

            var text = textGO.AddComponent<Text>();
            text.text = defaultText;
            text.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            text.fontSize = 20;
            text.color = Color.white;
            text.alignment = TextAnchor.MiddleLeft;

            xPos += 170;
        }

        private static void CreateCollectButton(GameObject canvas)
        {
            var btnGO = new GameObject("CollectAllButton");
            btnGO.transform.SetParent(canvas.transform, false);

            var rt = btnGO.AddComponent<RectTransform>();
            rt.anchorMin = new Vector2(1, 0);
            rt.anchorMax = new Vector2(1, 0);
            rt.pivot = new Vector2(1, 0);
            rt.sizeDelta = new Vector2(160, 50);
            rt.anchoredPosition = new Vector2(-20, 20);

            var img = btnGO.AddComponent<Image>();
            img.color = new Color(0.2f, 0.7f, 0.3f);

            var btn = btnGO.AddComponent<Button>();

            var textGO = new GameObject("Text");
            textGO.transform.SetParent(btnGO.transform, false);
            var textRT = textGO.AddComponent<RectTransform>();
            textRT.anchorMin = Vector2.zero;
            textRT.anchorMax = Vector2.one;
            textRT.sizeDelta = Vector2.zero;

            var text = textGO.AddComponent<Text>();
            text.text = "全部收集";
            text.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            text.fontSize = 22;
            text.color = Color.white;
            text.alignment = TextAnchor.MiddleCenter;
        }

        #endregion
    }
}

